 id: "Ω_valence",
 positiveComponent: Math.pow(RECURSION_FACTOR, 3), // Δ⁺³
 negativeComponent: -1 * Math.pow(RECURSION_FACTOR, 2), // Δ⁻²
 entropyFactor: Xi0.stability * 3,
 conflictLevel: 0.85,
 formula: "∂(Δ⁺³ ⊕ Δ⁻²) ⋅ φ(Ξ₀)"
};
// Apply meta-valence to produce Ξ₄′ := Ξ₄ + Ω_valence
