console.log(`Resonance Window: [${resonanceWindow.lowerBound}, ${resonanceWindow.upperBound.toFixed(4)}]`);
console.log(`Critical Point: τ = ${resonanceWindow.criticalPoint.toFixed(4)}`);
console.log(`Collapse Point: τ = ${resonanceWindow.collapsePoint.toFixed(4)}`);
// Collapse trajectory vectors
console.log("\n=== COLLAPSE TRAJECTORY VECTORS ===");
console.log(`Direction: [${distortionGradient.directionVector.map(v => v.toFixed(4)).join(", ")}]`);
console.log(`Magnitude: ${distortionGradient.magnitude.toFixed(4)}`);
