console.log(`Average Fork Stability: ${totalSystemStability.averageForkStability.toFixed(4)}`);
console.log(`Integrity Trend: [${totalSystemStability.integrityTrend.map(i => i.toFixed(4)).join(" → ")}]`);
console.log(`Projected Equilibrium Point: ${totalSystemStability.projectedEquilibrium.toFixed(4)}`);
console.log(`System Status: ${totalSystemStability.systemStatus}`);
// Final assessment
